def apply_theme_change(gui):
    theme = gui.theme_dropdown.get()
    
    if theme == "Dark Classic":
        gui.style.configure('.', background="#2b2b2b", foreground="#ffffff")
        gui.style.configure('TNotebook', background="#2b2b2b")
        gui.style.configure('TNotebook.Tab', background="#3e3e3e", foreground="#ffffff")
        gui.style.configure('Treeview', background="#1e1e1e", fieldbackground="#1e1e1e", foreground="#ffffff")
        gui.style.configure('Treeview.Heading', background="#3e3e3e", foreground="#ffffff")
        
        for tab in [gui.TNotebook_all_Dask, gui.TNotebook_all_white, gui.TNotebook_all_settings, gui.TNotebook_all_Games]:
            tab.configure(background="#2b2b2b")
            
        for widget in [gui.Label_header, gui.Label_Safe, gui.Label_Junk, gui.Label_inspector, gui.Label_console, gui.Label_Installed_Games, gui.Label_Theme, gui.Label_Exception, gui.Checkbutton_StartUp, gui.Checkbutton_live, gui.Checkbutton_Game_mode, gui.Label_BackJunk]:
            widget.configure(background="#2b2b2b", fg="#ffffff", activebackground="#2b2b2b", activeforeground="#ffffff")
            
        gui.Scrolledtext_console.configure(bg="#1e1e1e", fg="#00ff00")
        gui.Scrolledtext_inspector.configure(bg="#1e1e1e", fg="#ffffff")
        
    elif theme == "Light Modern":
        gui.style.configure('.', background="#f5f6fa", foreground="#2c3e50")
        gui.style.configure('TNotebook', background="#f5f6fa")
        gui.style.configure('TNotebook.Tab', background="#dcdde1", foreground="#2c3e50")
        gui.style.configure('Treeview', background="#ffffff", fieldbackground="#ffffff", foreground="#1b1b1b")
        gui.style.configure('Treeview.Heading', background="#dcdde1", foreground="#2c3e50")
        
        for tab in [gui.TNotebook_all_Dask, gui.TNotebook_all_white, gui.TNotebook_all_settings, gui.TNotebook_all_Games]:
            tab.configure(background="#f5f6fa")
            
        for widget in [gui.Label_header, gui.Label_Safe, gui.Label_Junk, gui.Label_inspector, gui.Label_console, gui.Label_Installed_Games, gui.Label_Theme, gui.Label_Exception, gui.Checkbutton_StartUp, gui.Checkbutton_live, gui.Checkbutton_Game_mode, gui.Label_BackJunk]:
            widget.configure(background="#f5f6fa", fg="#2c3e50", activebackground="#f5f6fa", activeforeground="#2c3e50")
            
        gui.Scrolledtext_console.configure(bg="#ffffff", fg="#1b1b1b")
        gui.Scrolledtext_inspector.configure(bg="#ffffff", fg="#1b1b1b")
        
    log_to_console(gui, f"Visual Theme configuration swapped to: {theme}")

def save_config_state(gui):
    payload = {
        "whitelist": system_whitelist,
        "exceptions": game_exceptions,
        "games_list": installed_games_list,
        "theme": gui.theme_dropdown.get(),
        "startup_sweep": gui.che73.get(),
        "live_refresh": gui.che49.get(),
        "game_mode": gui.che52.get()
    }
    try:
        with open(CONFIG_FILE, 'w') as f:
            json.dump(payload, f, indent=4)
        messagebox.showinfo("Config Manager", "Application configurations preserved dynamically.")
        
        global live_refresh_job
        if gui.che49.get() == 1 and not live_refresh_job:
            log_to_console(gui, "🔄 Real-time Live Refresh Active [5s Loops].")
            run_live_loop(gui)
        elif gui.che49.get() == 0 and live_refresh_job:
            root.after_cancel(live_refresh_job)
            live_refresh_job = None
            log_to_console(gui, "⏱️ Real-time Live Refresh Disabled.")
    except Exception as ex:
        messagebox.showerror("Config Error", f"Could not preserve configuration parameters: {str(ex)}")

def run_live_loop(gui):
    global live_refresh_job
    if gui.che49.get() == 1:
        handle_scan(gui)
        live_refresh_job = root.after(5000, lambda: run_live_loop(gui))

def load_persistent_config(gui):
    global system_whitelist, game_exceptions, installed_games_list, live_refresh_job
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, 'r') as f:
                data = json.load(f)
            system_whitelist = data.get("whitelist", system_whitelist)
            game_exceptions = data.get("exceptions", game_exceptions)
            installed_games_list = data.get("games_list", [])
            gui.theme_dropdown.set(data.get("theme", "Dark Classic"))
            gui.che73.set(data.get("startup_sweep", 0))
            gui.che49.set(data.get("live_refresh", 0))
            gui.che52.set(data.get("game_mode", 0))
            
            if gui.che49.get() == 1 and not live_refresh_job:
                run_live_loop(gui)
            apply_theme_change(gui)
        except Exception:
            pass
            
    gui.Scrolledlist_WhiteLists.delete(0, tk.END)
    for entry in system_whitelist: 
        gui.Scrolledlist_WhiteLists.insert(tk.END, entry)
    refresh_exceptions_ui(gui)
    
    for row in gui.Scrolledtree_installed_games.get_children(): 
        gui.Scrolledtree_installed_games.delete(row)
        
    for game in installed_games_list:
        title = os.path.splitext(game)[0].replace("_", " ").title()
        gui.Scrolledtree_installed_games.insert("", tk.END, text=title, values=("SAVED", game))

if __name__ == '__main__':
    main()